const book: BibleBook = {
  id: 'james',
  name: 'Tiago',
  englishName: 'James',
  testament: 'new',
  chapters: {
    1: [
      { v: 1, en: 'James, a servant of God and of the Lord Jesus Christ, to the twelve tribes which are in the Dispersion: Greetings.', pt: 'Tiago, servo de Deus e do Senhor Jesus Cristo, às doze tribos da Dispersão, saúde.' },
      { v: 2, en: 'Count it all joy, my brothers, when you fall into various temptations,', pt: 'Meus irmãos, tende por motivo de grande gozo o passardes por várias provações,' },
      { v: 3, en: 'knowing that the testing of your faith produces endurance.', pt: 'sabendo que a aprovação da vossa fé produz a perseverança;' },
      { v: 4, en: 'Let endurance have its perfect work, that you may be perfect and complete, lacking in nothing.', pt: 'e a perseverança tenha a sua obra perfeita, para que sejais perfeitos e completos, não faltando em coisa alguma.' },
      { v: 5, en: 'But if any of you lacks wisdom, let him ask of God, who gives to all liberally and without reproach; and it will be given to him.', pt: 'Ora, se algum de vós tem falta de sabedoria, peça-a a Deus, que a todos dá liberalmente e não censura, e ser-lhe-á dada.' },
      { v: 6, en: 'But let him ask in faith, without any doubting, for he who doubts is like a wave of the sea, driven by the wind and tossed.', pt: 'Peça-a, porém, com fé, não duvidando; pois aquele que duvida é semelhante à onda do mar, que é sublevada e agitada pelo vento.' },
      { v: 7, en: 'For that man shouldn’t think that he will receive anything from the Lord.', pt: 'Não pense tal homem que receberá do Senhor alguma coisa,' },
      { v: 8, en: 'He is a double-minded man, unstable in all his ways.', pt: 'homem vacilante que é, e inconstante em todos os seus caminhos.' },
      { v: 9, en: 'But let the brother in humble circumstances glory in his high position;', pt: 'Mas o irmão de condição humilde glorie-se na sua exaltação,' },
      { v: 10, en: 'and the rich, in that he is made humble, because like the flower in the grass, he will pass away.', pt: 'e o rico no seu abatimento; porque ele passará como a flor da erva.' },
      { v: 11, en: 'For the sun arises with the scorching wind, and withers the grass, and the flower in it falls, and the beauty of its appearance perishes. So also will the rich man fade away in his pursuits.', pt: 'Pois o sol se levanta em seu ardor e faz secar a erva; a sua flor cai e a beleza do seu aspecto perece; assim murchará também o rico em seus caminhos.' },
      { v: 12, en: 'Blessed is the man who endures temptation, for when he has been approved, he will receive the crown of life, which the Lord promised to those who love him.', pt: 'Bem-aventurado o homem que suporta a provação; porque, depois de aprovado, receberá a coroa da vida, que o Senhor prometeu aos que o amam.' },
      { v: 13, en: 'Let no man say when he is tempted, “I am tempted by God,” for God can’t be tempted by evil, and he himself tempts no one.', pt: 'Ninguém, sendo tentado, diga: Sou tentado por Deus; porque Deus não pode ser tentado pelo mal e ele a ninguém tenta.' },
      { v: 14, en: 'But each one is tempted when he is drawn away by his own lust, and enticed.', pt: 'Cada um, porém, é tentado, quando atraído e engodado pela sua própria concupiscência;' },
      { v: 15, en: 'Then the lust, when it has conceived, bears sin; and the sin, when it is full grown, produces death.', pt: 'então a concupiscência, havendo concebido, dá à luz o pecado; e o pecado, sendo consumado, gera a morte.' },
      { v: 16, en: 'Don’t be deceived, my beloved brothers.', pt: 'Não vos enganeis, meus amados irmãos.' },
      { v: 17, en: 'Every good gift and every perfect gift is from above, coming down from the Father of lights, with whom can be no variation, nor turning shadow.', pt: 'Toda boa dádiva e todo dom perfeito vêm do alto, descendo do Pai das luzes, em quem não há mudança nem sombra de variação.' },
      { v: 18, en: 'Of his own will he gave birth to us by the word of truth, that we should be a kind of first fruits of his creatures.', pt: 'Segundo a sua própria vontade, ele nos gerou pela palavra da verdade, para que fôssemos como que primícias das suas criaturas.' },
      { v: 19, en: 'So, then, my beloved brothers, let every man be swift to hear, slow to speak, and slow to anger;', pt: 'Sabei isto, meus amados irmãos: Todo homem seja pronto para ouvir, tardio para falar e tardio para se irar.' },
      { v: 20, en: 'for the anger of man doesn’t produce the righteousness of God.', pt: 'Porque a ira do homem não opera a justiça de Deus.' },
      { v: 21, en: 'Therefore, putting away all filthiness and overflowing of wickedness, receive with humility the implanted word, which is able to save your souls.', pt: 'Pelo que, despojando-vos de toda sorte de imundícia e de todo vestígio do mal, recebei com mansidão a palavra em vós implantada, a qual é poderosa para salvar as vossas almas.' },
      { v: 22, en: 'But be doers of the word, and not only hearers, deluding your own selves.', pt: 'E sede cumpridores da palavra e não somente ouvintes, enganando-vos a vós mesmos.' },
      { v: 23, en: 'For if anyone is a hearer of the word and not a doer, he is like a man looking at his natural face in a mirror;', pt: 'Pois se alguém é ouvinte da palavra e não cumpridor, é semelhante a um homem que contempla no espelho o seu rosto natural;' },
      { v: 24, en: 'for he sees himself, and goes away, and immediately forgets what kind of man he was.', pt: 'porque se contempla a si mesmo e vai-se, e logo se esquece de como era.' },
      { v: 25, en: 'But he who looks into the perfect law of freedom, and continues, not being a hearer who forgets, but a doer of the work, this man will be blessed in what he does.', pt: 'Entretanto aquele que atenta bem para a lei perfeita, a da liberdade, e nela persevera, não sendo ouvinte esquecido, mas executor da obra, este será bem-aventurado no que fizer.' },
      { v: 26, en: 'If anyone among you thinks himself to be religious while he doesn’t bridle his tongue, but deceives his heart, this man’s religion is worthless.', pt: 'Se alguém cuida ser religioso e não refreia a sua língua, mas engana o seu coração, a sua religião é vã.' },
      { v: 27, en: 'Pure religion and undefiled before our God and Father is this: to visit the fatherless and widows in their affliction, and to keep oneself unstained by the world.', pt: 'A religião pura e imaculada diante de nosso Deus e Pai é esta: Visitar os órfãos e as viúvas nas suas aflições e guardar-se isento da corrupção do mundo.' },
    ],
    2: [
      { v: 1, en: 'My brothers, don’t hold the faith of our Lord Jesus Christ of glory with partiality.', pt: 'Meus irmãos, não tenhais a fé em nosso Senhor Jesus Cristo, Senhor da glória, em acepção de pessoas.' },
      { v: 2, en: 'For if a man with a gold ring, in fine clothing, comes into your synagogue, and a poor man in filthy clothing also comes in;', pt: 'Porque, se entrar na vossa reunião algum homem com anel de ouro no dedo e com traje esplêndido, e entrar também algum pobre com traje sórdido.' },
      { v: 3, en: 'and you pay special attention to him who wears the fine clothing, and say, “Sit here in a good place”; and you tell the poor man, “Stand there,” or “Sit by my footstool”;', pt: 'e atentardes para o que vem com traje esplêndido e lhe disserdes: Senta-te aqui num lugar de honra; e disserdes ao pobre: Fica em pé, ou senta-te abaixo do escabelo dos meus pés,' },
      { v: 4, en: 'haven’t you shown partiality among yourselves, and become judges with evil thoughts?', pt: 'não fazeis, porventura, distinção entre vós mesmos e não vos tornais juízes movidos de maus pensamentos?' },
      { v: 5, en: 'Listen, my beloved brothers. Didn’t God choose those who are poor in this world to be rich in faith, and heirs of the Kingdom which he promised to those who love him?', pt: 'Ouvi, meus amados irmãos. Não escolheu Deus os que são pobres quanto ao mundo para fazê-los ricos na fé e herdeiros do reino que prometeu aos que o amam?' },
      { v: 6, en: 'But you have dishonored the poor man. Don’t the rich oppress you, and personally drag you before the courts?', pt: 'Mas vós desonrastes o pobre. Porventura não são os ricos os que vos oprimem e os que vos arrastam aos tribunais?' },
      { v: 7, en: 'Don’t they blaspheme the honorable name by which you are called?', pt: 'Não blasfemam eles o bom nome pelo qual sois chamados?' },
      { v: 8, en: 'However, if you fulfill the royal law, according to the Scripture, “You shall love your neighbor as yourself,” you do well.', pt: 'Todavia, se estais cumprindo a lei real segundo a escritura: Amarás ao teu próximo como a ti mesmo, fazeis bem.' },
      { v: 9, en: 'But if you show partiality, you commit sin, being convicted by the law as transgressors.', pt: 'Mas se fazeis acepção de pessoas, cometeis pecado, sendo por isso condenados pela lei como transgressores.' },
      { v: 10, en: 'For whoever keeps the whole law, and yet stumbles in one point, he has become guilty of all.', pt: 'Pois qualquer que guardar toda a lei, mas tropeçar em um só ponto, tem-se tornado culpado de todos.' },
      { v: 11, en: 'For he who said, “Do not commit adultery,” also said, “Do not commit murder.” Now if you do not commit adultery, but murder, you have become a transgressor of the law.', pt: 'Porque o mesmo que disse: Não adulterarás, também disse: Não matarás. Ora, se não cometes adultério, mas és homicida, te hás tornado transgressor da lei.' },
      { v: 12, en: 'So speak, and so do, as men who are to be judged by a law of freedom.', pt: 'Falai de tal maneira e de tal maneira procedei, como havendo de ser julgados pela lei da liberdade.' },
      { v: 13, en: 'For judgment is without mercy to him who has shown no mercy. Mercy triumphs over judgment.', pt: 'Porque o juízo será sem misericórdia para aquele que não usou de misericórdia; a misericórdia triunfa sobre o juízo.' },
      { v: 14, en: 'What good is it, my brothers, if a man says he has faith, but has no works? Can faith save him?', pt: 'Que proveito há, meus irmãos se alguém disser que tem fé e não tiver obras? Porventura essa fé pode salvá-lo?' },
      { v: 15, en: 'And if a brother or sister is naked and in lack of daily food,', pt: 'Se um irmão ou uma irmã estiverem nus e tiverem falta de mantimento cotidiano.' },
      { v: 16, en: 'and one of you tells them, “Go in peace, be warmed and filled”; and yet you didn’t give them the things the body needs, what good is it?', pt: 'e algum de vós lhes disser: Ide em paz, aquentai-vos e fartai-vos; e não lhes derdes as coisas necessárias para o corpo, que proveito há nisso?' },
      { v: 17, en: 'Even so faith, if it has no works, is dead in itself.', pt: 'Assim também a fé, se não tiver obras, é morta em si mesma.' },
      { v: 18, en: 'Yes, a man will say, “You have faith, and I have works.” Show me your faith without works, and I by my works will show you my faith.', pt: 'Mas dirá alguém: Tu tens fé, e eu tenho obras; mostra-me a tua fé sem as obras, e eu te mostrarei a minha fé pelas minhas obras.' },
      { v: 19, en: 'You believe that God is one. You do well. The demons also believe, and shudder.', pt: 'Crês tu que Deus é um só? Fazes bem; os demônios também o crêem, e estremecem.' },
      { v: 20, en: 'But do you want to know, vain man, that faith apart from works is dead?', pt: 'Mas queres saber, ó homem vão, que a fé sem as obras é estéril?' },
      { v: 21, en: 'Wasn’t Abraham our father justified by works, in that he offered up Isaac his son on the altar?', pt: 'Porventura não foi pelas obras que nosso pai Abraão foi justificado quando ofereceu sobre o altar seu filho Isaque?' },
      { v: 22, en: 'You see that faith worked with his works, and by works faith was perfected;', pt: 'Vês que a fé cooperou com as suas obras, e que pelas obras a fé foi aperfeiçoada;' },
      { v: 23, en: 'and the Scripture was fulfilled which says, “Abraham believed God, and it was accounted to him as righteousness”; and he was called the friend of God.', pt: 'e se cumpriu a escritura que diz: E creu Abraão a Deus, e isso lhe foi imputado como justiça, e foi chamado amigo de Deus.' },
      { v: 24, en: 'You see then that by works, a man is justified, and not only by faith.', pt: 'Vedes então que é pelas obras que o homem é justificado, e não somente pela fé.' },
      { v: 25, en: 'In the same way, wasn’t Rahab the prostitute also justified by works, in that she received the messengers, and sent them out another way?', pt: 'E de igual modo não foi a meretriz Raabe também justificada pelas obras, quando acolheu os espias, e os fez sair por outro caminho?' },
      { v: 26, en: 'For as the body apart from the spirit is dead, even so faith apart from works is dead.', pt: 'Porque, assim como o corpo sem o espírito está morto, assim também a fé sem obras é morta.' },
    ],
    3: [
      { v: 1, en: 'Let not many of you be teachers, my brothers, knowing that we will receive heavier judgment.', pt: 'Meus irmãos, não sejais muitos de vós mestres, sabendo que receberemos um juízo mais severo.' },
      { v: 2, en: 'For in many things we all stumble. If anyone doesn’t stumble in word, the same is a perfect man, able to bridle the whole body also.', pt: 'Pois todos tropeçamos em muitas coisas. Se alguém não tropeça em palavra, esse é homem perfeito, e capaz de refrear também todo o corpo.' },
      { v: 3, en: 'Indeed, we put bits into the horses’ mouths so that they may obey us, and we guide their whole body.', pt: 'Ora, se pomos freios na boca dos cavalos, para que nos obedeçam, então conseguimos dirigir todo o seu corpo.' },
      { v: 4, en: 'Behold, the ships also, though they are so big and are driven by fierce winds, are yet guided by a very small rudder, wherever the pilot desires.', pt: 'Vede também os navios que, embora tão grandes e levados por impetuosos ventos, com um pequenino leme se voltam para onde quer o impulso do timoneiro.' },
      { v: 5, en: 'So the tongue is also a little member, and boasts great things. See how a small fire can spread to a large forest!', pt: 'Assim também a língua é um pequeno membro, e se gaba de grandes coisas. Vede quão grande bosque um tão pequeno fogo incendeia.' },
      { v: 6, en: 'And the tongue is a fire. The world of iniquity among our members is the tongue, which defiles the whole body, and sets on fire the course of nature, and is set on fire by Gehenna.', pt: 'A língua também é um fogo; sim, a língua, qual mundo de iniqüidade, colocada entre os nossos membros, contamina todo o corpo, e inflama o curso da natureza, sendo por sua vez inflamada pelo inferno.' },
      { v: 7, en: 'For every kind of animal, bird, creeping thing, and sea creature, is tamed, and has been tamed by mankind;', pt: 'Pois toda espécie tanto de feras, como de aves, tanto de répteis como de animais do mar, se doma, e tem sido domada pelo gênero humano;' },
      { v: 8, en: 'but nobody can tame the tongue. It is a restless evil, full of deadly poison.', pt: 'mas a língua, nenhum homem a pode domar. É um mal irrefreável; está cheia de peçonha mortal.' },
      { v: 9, en: 'With it we bless our God and Father, and with it we curse men, who are made in the image of God.', pt: 'Com ela bendizemos ao Senhor e Pai, e com ela amaldiçoamos os homens, feitos à semelhança de Deus.' },
      { v: 10, en: 'Out of the same mouth comes blessing and cursing. My brothers, these things ought not to be so.', pt: 'Da mesma boca procede bênção e maldição. Não convém, meus irmãos, que se faça assim.' },
      { v: 11, en: 'Does a spring send out from the same opening fresh and bitter water?', pt: 'Porventura a fonte deita da mesma abertura água doce e água amargosa?' },
      { v: 12, en: 'Can a fig tree, my brothers, yield olives, or a vine figs? Thus no spring yields both salt water and fresh water.', pt: 'Meus irmãos, pode acaso uma figueira produzir azeitonas, ou uma videira figos? Nem tampouco pode uma fonte de água salgada dar água doce.' },
      { v: 13, en: 'Who is wise and understanding among you? Let him show by his good conduct that his deeds are done in gentleness of wisdom.', pt: 'Quem dentre vós é sábio e entendido? Mostre pelo seu bom procedimento as suas obras em mansidão de sabedoria.' },
      { v: 14, en: 'But if you have bitter jealousy and selfish ambition in your heart, don’t boast and don’t lie against the truth.', pt: 'Mas, se tendes amargo ciúme e sentimento faccioso em vosso coração, não vos glorieis, nem mintais contra a verdade.' },
      { v: 15, en: 'This wisdom is not that which comes down from above, but is earthly, sensual, and demonic.', pt: 'Essa não é a sabedoria que vem do alto, mas é terrena, animal e diabólica.' },
      { v: 16, en: 'For where jealousy and selfish ambition are, there is confusion and every evil deed.', pt: 'Porque onde há ciúme e sentimento faccioso, aí há confusão e toda obra má.' },
      { v: 17, en: 'But the wisdom that is from above is first pure, then peaceful, gentle, reasonable, full of mercy and good fruits, without partiality, and without hypocrisy.', pt: 'Mas a sabedoria que vem do alto é, primeiramente, pura, depois pacífica, moderada, tratável, cheia de misericórdia e de bons frutos, sem parcialidade, e sem hipocrisia.' },
      { v: 18, en: 'Now the fruit of righteousness is sown in peace by those who make peace.', pt: 'Ora, o fruto da justiça semeia-se em paz para aqueles que promovem a paz.' },
    ],
    4: [
      { v: 1, en: 'Where do wars and fightings among you come from? Don’t they come from your pleasures that war in your members?', pt: 'Donde vêm as guerras e contendas entre vós? Porventura não vêm disto, dos vossos deleites, que nos vossos membros guerreiam?' },
      { v: 2, en: 'You lust, and don’t have. You murder and covet, and can’t obtain. You fight and make war. You don’t have, because you don’t ask.', pt: 'Cobiçais e nada tendes; logo matais. Invejais, e não podeis alcançar; logo combateis e fazeis guerras. Nada tendes, porque não pedis.' },
      { v: 3, en: 'You ask, and don’t receive, because you ask with wrong motives, so that you may spend it on your pleasures.', pt: 'Pedis e não recebeis, porque pedis mal, para o gastardes em vossos deleites.' },
      { v: 4, en: 'You adulterers and adulteresses, don’t you know that friendship with the world is hostility toward God? Whoever therefore wants to be a friend of the world makes himself an enemy of God.', pt: 'Infiéis, não sabeis que a amizade do mundo é inimizade contra Deus? Portanto qualquer que quiser ser amigo do mundo constitui-se inimigo de Deus.' },
      { v: 5, en: 'Or do you think that the Scripture says in vain, “The Spirit who lives in us yearns jealously”?', pt: 'Ou pensais que em vão diz a escritura: O Espírito que ele fez habitar em nós anseia por nós até o ciúme?' },
      { v: 6, en: 'But he gives more grace. Therefore it says, “God resists the proud, but gives grace to the humble.”', pt: 'Todavia, dá maior graça. Portanto diz: Deus resiste aos soberbos; dá, porém, graça aos humildes.' },
      { v: 7, en: 'Be subject therefore to God. Resist the devil, and he will flee from you.', pt: 'Sujeitai-vos, pois, a Deus; mas resisti ao Diabo, e ele fugirá de vós.' },
      { v: 8, en: 'Draw near to God, and he will draw near to you. Cleanse your hands, you sinners; and purify your hearts, you double-minded.', pt: 'Chegai-vos para Deus, e ele se chegará para vós. Limpai as mãos, pecadores; e, vós de espírito vacilante, purificai os corações.' },
      { v: 9, en: 'Lament, mourn, and weep. Let your laughter be turned to mourning, and your joy to gloom.', pt: 'Senti as vossas misérias, lamentai e chorai; torne-se o vosso riso em pranto, e a vossa alegria em tristeza.' },
      { v: 10, en: 'Humble yourselves in the sight of the Lord, and he will exalt you.', pt: 'Humilhai-vos perante o Senhor, e ele vos exaltará.' },
      { v: 11, en: 'Don’t speak against one another, brothers. He who speaks against a brother and judges his brother, speaks against the law and judges the law. But if you judge the law, you are not a doer of the law, but a judge.', pt: 'Irmãos, não faleis mal uns dos outros. Quem fala mal de um irmão, e julga a seu irmão, fala mal da lei, e julga a lei; ora, se julgas a lei, não és observador da lei, mas juiz.' },
      { v: 12, en: 'Only one is the lawgiver, who is able to save and to destroy. But who are you to judge another?', pt: 'Há um só legislador e juiz, aquele que pode salvar e destruir; tu, porém, quem és, que julgas ao próximo?' },
      { v: 13, en: 'Come now, you who say, “Today or tomorrow let’s go into this city, and spend a year there, trade, and make a profit.”', pt: 'Eia agora, vós que dizeis: Hoje ou amanhã iremos a tal cidade, lá passaremos um ano, negociaremos e ganharemos.' },
      { v: 14, en: 'Whereas you don’t know what your life will be like tomorrow. For what is your life? For you are a vapor, that appears for a little time, and then vanishes away.', pt: 'No entanto, não sabeis o que sucederá amanhã. Que é a vossa vida? Sois um vapor que aparece por um pouco, e logo se desvanece.' },
      { v: 15, en: 'For you ought to say, “If the Lord wills, we will both live, and do this or that.”', pt: 'Em lugar disso, devíeis dizer: Se o Senhor quiser, viveremos e faremos isto ou aquilo.' },
      { v: 16, en: 'But now you glory in your boasting. All such boasting is evil.', pt: 'Mas agora vos jactais das vossas presunções; toda jactância tal como esta é maligna.' },
      { v: 17, en: 'To him therefore who knows to do good, and doesn’t do it, to him it is sin.', pt: 'Aquele, pois, que sabe fazer o bem e não o faz, comete pecado.' },
    ],
    5: [
      { v: 1, en: 'Come now, you rich, weep and howl for your miseries that are coming on you.', pt: 'Eia agora, vós ricos, chorai e pranteai, por causa das desgraças que vos sobrevirão.' },
      { v: 2, en: 'Your riches are corrupted and your garments are moth-eaten.', pt: 'As vossas riquezas estão apodrecidas, e as vossas vestes estão roídas pela traça.' },
      { v: 3, en: 'Your gold and your silver are corroded, and their corrosion will be for a testimony against you, and will eat your flesh like fire. You have laid up your treasure in the last days.', pt: 'O vosso ouro e a vossa prata estão enferrujados; e a sua ferrugem dará testemunho contra vós, e devorará as vossas carnes como fogo. Entesourastes para os últimos dias.' },
      { v: 4, en: 'Behold, the wages of the laborers who mowed your fields, which you have kept back by fraud, cry out, and the cries of those who reaped have entered into the ears of the Lord of Armies.', pt: 'Eis que o salário que fraudulentamente retivestes aos trabalhadores que ceifaram os vossos campos clama, e os clamores dos ceifeiros têm chegado aos ouvidos do Senhor dos exércitos.' },
      { v: 5, en: 'You have lived in luxury on the earth, and taken your pleasure. You have nourished your hearts as in a day of slaughter.', pt: 'Deliciosamente vivestes sobre a terra, e vos deleitastes; cevastes os vossos corações no dia da matança.' },
      { v: 6, en: 'You have condemned, you have murdered the righteous one. He doesn’t resist you.', pt: 'Condenastes e matastes o justo; ele não vos resiste.' },
      { v: 7, en: 'Be patient therefore, brothers, until the coming of the Lord. Behold, the farmer waits for the precious fruit of the earth, being patient over it, until it receives the early and late rain.', pt: 'Portanto, irmãos, sede pacientes até a vinda do Senhor. Eis que o lavrador espera o precioso fruto da terra, aguardando-o com paciência, até que receba as primeiras e as últimas chuvas.' },
      { v: 8, en: 'You also be patient. Establish your hearts, for the coming of the Lord is at hand.', pt: 'Sede vós também pacientes; fortalecei os vossos corações, porque a vinda do Senhor está próxima.' },
      { v: 9, en: 'Don’t grumble, brothers, against one another, so that you won’t be judged. Behold, the judge stands at the door.', pt: 'Não vos queixeis, irmãos, uns dos outros, para que não sejais julgados. Eis que o juiz está à porta.' },
      { v: 10, en: 'Take, brothers, for an example of suffering and of perseverance, the prophets who spoke in the name of the Lord.', pt: 'Irmãos, tomai como exemplo de sofrimento e paciência os profetas que falaram em nome do Senhor.' },
      { v: 11, en: 'Behold, we call them blessed who endured. You have heard of the perseverance of Job, and have seen the Lord in the outcome, and how the Lord is full of compassion and mercy.', pt: 'Eis que chamamos bem-aventurados os que suportaram aflições. Ouvistes da paciência de Jó, e vistes o fim que o Senhor lhe deu, porque o Senhor é cheio de misericórdia e compaixão.' },
      { v: 12, en: 'But above all things, my brothers, don’t swear— not by heaven, or by the earth, or by any other oath; but let your “yes” be “yes”, and your “no”, “no”; so that you don’t fall into hypocrisy.', pt: 'Mas, sobretudo, meus irmãos, não jureis, nem pelo céu, nem pela terra, nem façais qualquer outro juramento; seja, porém, o vosso sim, sim, e o vosso não, não, para não cairdes em condenação.' },
      { v: 13, en: 'Is any among you suffering? Let him pray. Is any cheerful? Let him sing praises.', pt: 'Está aflito alguém entre vós? Ore. Está alguém contente? Cante louvores.' },
      { v: 14, en: 'Is any among you sick? Let him call for the elders of the assembly, and let them pray over him, anointing him with oil in the name of the Lord,', pt: 'Está doente algum de vós? Chame os anciãos da igreja, e estes orem sobre ele, ungido-o com óleo em nome do Senhor;' },
      { v: 15, en: 'and the prayer of faith will heal him who is sick, and the Lord will raise him up. If he has committed sins, he will be forgiven.', pt: 'e a oração da fé salvará o doente, e o Senhor o levantará; e, se houver cometido pecados, ser-lhe-ão perdoados.' },
      { v: 16, en: 'Confess your offenses to one another, and pray for one another, that you may be healed. The insistent prayer of a righteous person is powerfully effective.', pt: 'Confessai, portanto, os vossos pecados uns aos outros, e orai uns pelos outros, para serdes curados. A súplica de um justo pode muito na sua atuação.' },
      { v: 17, en: 'Elijah was a man with a nature like ours, and he prayed earnestly that it might not rain, and it didn’t rain on the earth for three years and six months.', pt: 'Elias era homem sujeito às mesmas paixões que nós, e orou com fervor para que não chovesse, e por três anos e seis meses não choveu sobre a terra.' },
      { v: 18, en: 'He prayed again, and the sky gave rain, and the earth produced its fruit.', pt: 'E orou outra vez e o céu deu chuva, e a terra produziu o seu fruto.' },
      { v: 19, en: 'Brothers, if any among you wanders from the truth and someone turns him back,', pt: 'Meus irmãos, se alguém dentre vós se desviar da verdade e alguém o converter,' },
      { v: 20, en: 'let him know that he who turns a sinner from the error of his way will save a soul from death and will cover a multitude of sins.', pt: 'sabei que aquele que fizer converter um pecador do erro do seu caminho salvará da morte uma alma, e cobrirá uma multidão de pecados.' },
    ],
  },
};

export default book;
